function solve(nums) {
    const n = nums.length;
    if (n < 3) return 0;

    // The maximum number of peaks we can create is floor((n-2)/2) + 1
    // For n=3, max peaks = 1 (i=1)
    // For n=4, max peaks = 1 (i=1 or i=2)
    // For n=5, max peaks = 2 (i=1, i=3)
    // The maximum number of non-adjacent peaks is achieved by placing them at indices 1, 3, 5, ...
    // The indices for peaks are i where 1 <= i <= n-2.
    // If we choose i_1, i_2, ... such that i_{j+1} >= i_j + 2, then we maximize the count.
    // Maximum number of peaks is ceil((n-2)/2) if we start at 1, or floor((n-2)/2) + 1?
    // Let's just aim to maximize the count greedily or through DP/Greedy based on structure.

    // The problem structure suggests that to maximize peaks, we want them to be far apart,
    // so we aim for indices 1, 3, 5, ... as much as possible.
    // Let P be the set of indices we choose to be peaks: P = {i | 1 <= i <= n-2}.
    // If we choose i in P, we need nums[i] > nums[i-1] and nums[i] > nums[i+1].
    // To minimize cost, we should choose the maximum possible set of indices P such that no two are adjacent.
    // P_max = {1, 3, 5, ...} intersected with {1, ..., n-2}.
    // Max number of peaks = number of elements in P_max.
    const maxPeaks = Math.floor((n - 1) / 2);

    // If n=3, indices {1}. Max peaks = 1. floor((3-1)/2) = 1.
    // If n=4, indices {1, 2}. Max peaks = 1. floor((4-1)/2) = 1.
    // If n=5, indices {1, 2, 3}. Max peaks = 2. floor((5-1)/2) = 2.
    // If n=6, indices {1, 2, 3, 4}. Max peaks = 2. floor((6-1)/2) = 2.
    // This seems correct. We target the set of indices P_target = {1, 3, 5, ...} up to n-2.

    const targetIndices = [];
    for (let i = 1; i <= n - 2; i += 2) {
        targetIndices.push(i);
    }
    // If n=4, targetIndices = [1]. Max peaks = 1.
    // If n=5, targetIndices = [1, 3]. Max peaks = 2.

    // Since operations on nums[i] can affect the conditions for neighbors (i-1, i+1, i+2, ...),
    // and we want to minimize total operations, this suggests a greedy approach or DP.
    // Because increasing nums[i] only helps satisfy the peak condition for i, and potentially
    // helps satisfy the peak condition for its neighbors (i-1, i+1) if they are also targeted peaks,
    // we should process the target peaks in an order that minimizes cascading changes.

    // Let's fix the set of target peaks P = {1, 3, 5, ...}. We must achieve this count.
    // The cost is independent of the actual values, as long as the peak conditions are met.
    // To satisfy nums[i] > nums[i-1] and nums[i] > nums[i+1], we must ensure:
    // New nums[i] > nums[i-1] (potentially modified)
    // New nums[i] > nums[i+1] (potentially modified)

    // Since we are only allowed to *increase* values, and we want to minimize increases,
    // we should process the target indices in increasing order (1, 3, 5, ...).
    // When we modify nums[i], this change might affect the required modifications for nums[i+2] (if it's a target peak)
    // because nums[i+2] requires nums[i+2] > nums[i+1], and nums[i+1] might have been increased if it was modified for peak i.

    // Wait, if we only modify nums[i] for i in P_target, then neighbors (i-1, i+1) are not in P_target.
    // If i-1 or i+1 are not in P_target, we don't need to modify them to make *them* peaks.
    // But if we modify nums[i], it changes the required height for neighbors.

    // Consider i in P_target. We need nums[i] > nums[i-1] and nums[i] > nums[i+1].
    // nums[i-1] and nums[i+1] are neighbors of i, and they are NOT in P_target.
    // If we only increase nums[i], the required increase for nums[i] is:
    // Cost_i = max(0, nums[i-1] + 1 - nums[i], nums[i+1] + 1 - nums[i])

    // Since we process in increasing order (1, 3, 5, ...), when considering index i,
    // nums[i-1] and nums[i+1] might have been modified if they were targets themselves,
    // but they are not. They are neighbors of a target peak.

    // Let's re-examine the dependencies.
    // Target peaks P_target = {1, 3, 5, ...}.
    // For i in P_target:
    // 1. nums[i] > nums[i-1]
    // 2. nums[i] > nums[i+1]

    // If we modify nums[i] for i in P_target, we are only changing elements at target locations.
    // The neighbors (i-1) and (i+1) are at indices that are NOT in P_target.
    // Since we are only trying to maximize the count of peaks in P_target, we do not *need* to modify i-1 or i+1.
    // Any modification to nums[i-1] or nums[i+1] would only increase the cost unnecessarily, unless that modification is required to satisfy a peak condition for i.
    // Since the definition of a peak only depends on its immediate neighbors, and we are only increasing values,
    // if we only modify elements at indices in P_target, the values of neighbors nums[i-1] and nums[i+1] remain fixed at their initial values.

    // Therefore, the required increase for nums[i] is determined by the *initial* values of its neighbors.

    let totalOperations = 0;
    // Create a mutable copy of nums if we were worried about state, but since we assume only P_target elements are modified,
    // and neighbors are never in P_target, the initial values are sufficient.
    const currentNums = [...nums];

    for (const i of targetIndices) {
        const leftNeighbor = currentNums[i - 1];
        const rightNeighbor = currentNums[i + 1];
        const currentValue = currentNums[i];

        // Required value for nums[i] must be at least max(leftNeighbor + 1, rightNeighbor + 1)
        const requiredMin = Math.max(leftNeighbor + 1, rightNeighbor + 1);

        if (currentValue < requiredMin) {
            const increase = requiredMin - currentValue;
            totalOperations += increase;
            // Update the array to reflect the change, although it's not strictly necessary if we assume neighbors are never targets.
            // It is good practice to update it anyway, in case future logic depended on it.
            currentNums[i] += increase;
        }
    }

    // This greedy approach works because maximizing the count leads to a fixed set of non-adjacent target indices,
    // and the cost to make a specific peak independent of others (if neighbors aren't targets).

    return totalOperations;
}

