fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n < 3 {
        return 0;
    }

    // The maximum number of non-adjacent peaks achievable is by targeting indices 1, 3, 5, ...
    // Target indices i must satisfy 1 <= i <= n - 2.
    let mut target_indices = Vec::new();
    for i in (1..=n - 2).step_by(2) {
        target_indices.push(i);
    }

    // We need to calculate the minimum cost to make all elements at target_indices peaks.
    // Since we only increase values, and neighbors (i-1, i+1) are never target peaks,
    // the required increase for nums[i] is determined by the initial values of its neighbors.

    // We use a mutable copy of nums to track the current state, although for this specific strategy, 
    // only updates at target indices matter, and neighbors are never targeted.
    let mut current_nums = nums;
    let mut total_operations: i64 = 0;

    // Process targets in increasing order.
    for &i in &target_indices {
        let left_neighbor = current_nums[i - 1];
        let right_neighbor = current_nums[i + 1];
        let current_value = current_nums[i];

        // Required value for nums[i] must be strictly greater than both neighbors.
        // Required minimum value = max(neighbor_left + 1, neighbor_right + 1)
        let required_min = std::cmp::max(left_neighbor + 1, right_neighbor + 1);

        if current_value < required_min {
            let increase = required_min - current_value;
            total_operations += increase;
            // Update the array state
            current_nums[i] += increase;
        }
    }

    total_operations
}
