    // 1. nums[i] > nums[i-1]
    // 2. nums[i] > nums[i+1]

    // If we modify nums[i] for i in P_target, we are only changing elements at target locations.
    // The neighbors (i-1) and (i+1) are at indices that are NOT in P_target.
    // Since we are only trying to maximize the count of peaks in P_target, we do not *need* to modify i-1 or i+1.
    // Any modification to nums[i-1] or nums[i+1] would only increase the cost unnecessarily, unless that modification is required to satisfy a peak condition for i.
    // Since the definition of a peak only depends on its immediate neighbors, and we are only increasing values,
    // if we only modify elements at indices in P_target, the values of neighbors nums[i-1] and nums[i+1] remain fixed at their initial values.

    // Therefore, the required increase for nums[i] is determined by the *initial* values of its neighbors.

    let totalOperations = 0;
    // Create a mutable copy of nums if we were worried about state, but since we assume only P_target elements are modified,
    // and neighbors are never in P_target, the initial values are sufficient.
    const currentNums = [...nums];

    for (const i of targetIndices) {
        const leftNeighbor = currentNums[i - 1];
        const rightNeighbor = currentNums[i + 1];
        const currentValue = currentNums[i];

        // Required value for nums[i] must be at least max(leftNeighbor + 1, rightNeighbor + 1)
        const requiredMin = Math.max(leftNeighbor + 1, rightNeighbor + 1);

        if (currentValue < requiredMin) {
            const increase = requiredMin - currentValue;
            totalOperations += increase;
            // Update the array to reflect the change, although it's not strictly necessary if we assume neighbors are never targets.
            // It is good practice to update it anyway, in case future logic depended on it.
            currentNums[i] += increase;
        }
    }

    // This greedy approach works because maximizing the count leads to a fixed set of non-adjacent target indices,
    // and the cost to make a specific peak independent of others (if neighbors aren't targets).

    return totalOperations;
}
